    def xǁJujutsuVCSǁdetect_conflicts__mutmut_orig(self, workspace_path: Path) -> list[ConflictInfo]:
        """
        Detect conflicts in a workspace.

        In jj, conflicts are stored in commits rather than blocking operations.
        This method parses `jj status` to find conflicted files.

        Args:
            workspace_path: Path to the workspace

        Returns:
            List of ConflictInfo for all conflicted files
        """
        try:
            result = subprocess.run(
                ["jj", "status"],
                capture_output=True,
                text=True,
                encoding="utf-8",
                errors="replace",
                timeout=30,
                cwd=str(workspace_path),
            )

            if result.returncode != 0:
                return []

            conflicts = []
            # Parse jj status output
            # Conflicted files show as "C path/to/file"
            for line in result.stdout.strip().split("\n"):
                line = line.strip()
                if line.startswith("C "):
                    file_path = Path(line[2:].strip())
                    conflicts.append(
                        ConflictInfo(
                            file_path=file_path,
                            conflict_type=ConflictType.CONTENT,
                            line_ranges=None,
                            sides=2,  # Default, could be more in octopus merges
                            is_resolved=False,
                            our_content=None,
                            their_content=None,
                            base_content=None,
                        )
                    )

            # Also check the log for conflict indicator
            log_result = subprocess.run(
                ["jj", "log", "-r", "@", "--no-graph", "-T", 'if(conflict, "conflict", "") ++ "\n"'],
                capture_output=True,
                text=True,
                encoding="utf-8",
                errors="replace",
                timeout=10,
                cwd=str(workspace_path),
            )

            if log_result.returncode == 0 and "conflict" in log_result.stdout:
                # Current commit has conflicts
                # If we didn't find specific files, add a generic indicator
                if not conflicts:
                    conflicts.append(
                        ConflictInfo(
                            file_path=Path("."),
                            conflict_type=ConflictType.CONTENT,
                            line_ranges=None,
                            sides=2,
                            is_resolved=False,
                            our_content=None,
                            their_content=None,
                            base_content=None,
                        )
                    )

            return conflicts

        except (subprocess.TimeoutExpired, OSError):
            return []

