    def xǁJujutsuVCSǁhas_conflicts__mutmut_orig(self, workspace_path: Path) -> bool:
        """
        Check if workspace has any unresolved conflicts.

        Args:
            workspace_path: Path to the workspace

        Returns:
            True if conflicts exist, False otherwise
        """
        try:
            # Check current commit for conflict marker
            result = subprocess.run(
                ["jj", "log", "-r", "@", "--no-graph", "-T", 'if(conflict, "yes", "no") ++ "\n"'],
                capture_output=True,
                text=True,
                encoding="utf-8",
                errors="replace",
                timeout=10,
                cwd=str(workspace_path),
            )

            if result.returncode == 0 and "yes" in result.stdout:
                return True

            # Also check status for conflicted files
            status_result = subprocess.run(
                ["jj", "status"],
                capture_output=True,
                text=True,
                encoding="utf-8",
                errors="replace",
                timeout=10,
                cwd=str(workspace_path),
            )

            # Look for conflict indicator in status
            for line in status_result.stdout.split("\n"):
                if line.strip().startswith("C "):
                    return True

            return False

        except (subprocess.TimeoutExpired, OSError):
            return False

