    def xǁJujutsuVCSǁget_changes__mutmut_orig(
        self,
        repo_path: Path,
        revision_range: str | None = None,
        limit: int | None = None,
    ) -> list[ChangeInfo]:
        """
        Get list of changes/commits.

        Args:
            repo_path: Repository path
            revision_range: jj revset expression (e.g., "::@", "main..@")
            limit: Maximum number to return

        Returns:
            List of ChangeInfo
        """
        try:
            template = (
                'change_id ++ "|" ++ '
                'commit_id ++ "|" ++ '
                'description.first_line() ++ "|" ++ '
                'author.name() ++ "|" ++ '
                'author.email() ++ "|" ++ '
                'author.timestamp().format("%Y-%m-%dT%H:%M:%S%:z") ++ "|" ++ '
                'parents.map(|p| p.commit_id()).join(",") ++ "|" ++ '
                'if(conflict, "conflict", "") ++ "|" ++ '
                'if(empty, "empty", "") ++ "\n"'
            )

            cmd = ["jj", "log", "--no-graph", "-T", template]

            if revision_range:
                cmd.extend(["-r", revision_range])
            else:
                cmd.extend(["-r", "::@"])

            if limit:
                cmd.extend(["--limit", str(limit)])

            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                encoding="utf-8",
                errors="replace",
                timeout=60,
                cwd=str(repo_path),
            )

            if result.returncode != 0:
                return []

            changes = []
            for line in result.stdout.strip().split("\n"):
                if line:
                    change = self._parse_log_line_short(line)
                    if change:
                        changes.append(change)

            return changes

        except (subprocess.TimeoutExpired, OSError):
            return []

