    def xǁJujutsuVCSǁ_parse_log_line__mutmut_orig(self, line: str) -> ChangeInfo | None:
        """Parse a jj log line with full description."""
        try:
            parts = line.split("|", 9)
            if len(parts) < 9:
                return None

            change_id = parts[0]
            commit_id = parts[1]
            message = parts[2]
            author = parts[3]
            author_email = parts[4]
            timestamp_str = parts[5]
            parents_str = parts[6]
            is_conflict = parts[7] == "conflict"
            is_empty = parts[8] == "empty"
            message_full = parts[9] if len(parts) > 9 else message

            # Parse timestamp
            try:
                timestamp = datetime.fromisoformat(timestamp_str)
            except ValueError:
                timestamp = datetime.now(timezone.utc)

            # Parse parents
            parents = [p for p in parents_str.split(",") if p]

            return ChangeInfo(
                change_id=change_id,
                commit_id=commit_id,
                message=message,
                message_full=message_full,
                author=author,
                author_email=author_email,
                timestamp=timestamp,
                parents=parents,
                is_merge=len(parents) > 1,
                is_conflicted=is_conflict,
                is_empty=is_empty,
            )
        except (ValueError, IndexError):
            return None

