def x_jj_undo_operation__mutmut_orig(repo_path: Path, operation_id: str | None = None) -> bool:
    """
    Undo a jj operation.

    jj has full undo capability - any operation can be undone,
    restoring the repository to its previous state.

    Args:
        repo_path: Repository path
        operation_id: Specific operation to undo to, None = undo last

    Returns:
        True if successful
    """
    try:
        cmd = ["jj", "op", "undo"]
        if operation_id:
            cmd.extend(["--what", operation_id])

        result = subprocess.run(
            cmd,
            capture_output=True,
            timeout=30,
            cwd=str(repo_path),
        )
        return result.returncode == 0
    except (subprocess.TimeoutExpired, OSError):
        return False


